styles.content:
/* 全局重置和容器样式 */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  background: #f7f8fc;
  display: flex;
  justify-content: center;
  padding: 20px;
  min-height: 100vh;
}

#app {
  width: 100%;
  max-width: 900px;
}

.container {
  background: #ffffff;
  border-radius: 20px;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  padding: 28px 32px;
  transition: all 0.2s;
}

/* 用户输入区域 */
.user-inputs {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-bottom: 24px;
}

.user-input {
  background: #f0f4ff;
  padding: 14px 20px;
  border-radius: 16px;
  border-left: 4px solid #4a6cf7;
  font-size: 15px;
  line-height: 1.6;
  color: #1a2332;
  word-break: break-word;
}

.user-input div {
  margin-bottom: 4px;
}

.user-input div:last-child {
  margin-bottom: 0;
}

/* AI 思考区域 */
.ai-think {
  background: #f9faff;
  border-radius: 16px;
  margin-bottom: 20px;
  border: 1px solid #e9ecf5;
  overflow: hidden;
  transition: all 0.2s;
}

.think-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 20px;
  cursor: pointer;
  user-select: none;
  transition: background 0.15s;
  background: #f3f6fe;
}

.think-header:hover {
  background: #e8edfa;
}

.think-header span:first-child {
  font-weight: 600;
  color: #2d3a5e;
  font-size: 15px;
  letter-spacing: 0.3px;
}

.think-header span:last-child {
  font-size: 14px;
  color: #5a6b8a;
  transition: transform 0.2s;
}

.think-content {
  padding: 16px 22px 20px 22px;
  background: #ffffff;
  border-top: 1px solid #e9ecf5;
  font-size: 14.5px;
  line-height: 1.7;
  color: #2d3a5e;
  word-break: break-word;
  max-height: 400px;
  overflow-y: auto;
}

.think-content div {
  margin-bottom: 6px;
}

.think-content div:last-child {
  margin-bottom: 0;
}

/* 自定义滚动条 */
.think-content::-webkit-scrollbar {
  width: 6px;
}

.think-content::-webkit-scrollbar-track {
  background: #f0f2f7;
  border-radius: 8px;
}

.think-content::-webkit-scrollbar-thumb {
  background: #cdd4e6;
  border-radius: 8px;
}

.think-content::-webkit-scrollbar-thumb:hover {
  background: #b0b9d0;
}

/* AI 输出区域 */
.ai-output {
  background: #fafcff;
  padding: 18px 22px;
  border-radius: 16px;
  border: 1px solid #eef1f9;
  font-size: 15px;
  line-height: 1.7;
  color: #1a2332;
  word-break: break-word;
  margin-top: 8px;
}

.ai-output div {
  margin-bottom: 6px;
}

.ai-output div:last-child {
  margin-bottom: 0;
}

/* 响应式 */
@media (max-width: 600px) {
  body {
    padding: 12px;
  }

  .container {
    padding: 18px 16px;
  }

  .user-input {
    padding: 12px 16px;
    font-size: 14px;
  }

  .think-header {
    padding: 12px 16px;
  }

  .think-content {
    padding: 14px 16px 18px 16px;
    font-size: 14px;
  }

  .ai-output {
    padding: 14px 16px;
    font-size: 14px;
  }
}

scripts.content:
import { render } from 'preact';
import { html } from 'htm/preact';
import { useState, useEffect } from 'preact/hooks';

// 辅助函数：渲染带换行的文本
function TextWithBreaks({text}) {
  if (!text) return null;
  return text.split('\n').map((line) => {
    return html`<div>${line}</div>`;
  });
}

// 主应用组件
function App() {
  const [data, setData] = useState(window.__messageData?.["content"] ?? {
    inputs: [],
    output: "",
    reasoningContent: "",
  });
  const [isThinkVisible, setIsThinkVisible] = useState(false);
  useEffect(function() {
    function handleMessage(e) {
      setData(d => ({...d, ...e.data.data}));
    }

    window.addEventListener('message', handleMessage);
    return function() {
      window.removeEventListener('message', handleMessage);
    };
  }, []);


  // 使用 h 函数创建元素
  return html`
  <div class="container">
    ${data.inputs.length > 0 && html`
    <div class="user-inputs">
    ${data.inputs.map(u => html`<div class="user-input"><${TextWithBreaks} text=${u} /></div>`)}
    </div>`}
    ${data.reasoningContent && html`
    <div class="ai-think">
      <div class="think-header" onClick=${()=>setIsThinkVisible(!isThinkVisible)}>
        <span style="fontWeight:'bold'">'💭 思考过程'</span>
        <span>${isThinkVisible ? '▼' : '▶'}</span>
      </div>
      ${isThinkVisible && html`
      <div class=""think-content>
        <${TextWithBreaks} text=${data.reasoningContent} />
      </div>`}
    </div>`}
    ${data.output && html`
    <div class="ai-output">
        <${TextWithBreaks} text=${data.output} />
    </div>`}
  </div>
  `;
}

let root = document.createElement('div');
root.id = 'app';
document.body.appendChild(root)
render(html`<${App} />`, root);
